-apiVersion: v1
-kind: ConfigMap
-metadata:
-  name: nginx-config
-  namespace: wifi-densepose
-  labels:
-    app: wifi-densepose
-    component: nginx
-data:
-  nginx.conf: |
-    user nginx;
-    worker_processes auto;
-    error_log /var/log/nginx/error.log warn;
-    pid /var/run/nginx.pid;
-
-    events {
-        worker_connections 1024;
-        use epoll;
-        multi_accept on;
-    }
-
-    http {
-        include /etc/nginx/mime.types;
-        default_type application/octet-stream;
-
-        log_format main '$remote_addr - $remote_user [$time_local] "$request" '
-                        '$status $body_bytes_sent "$http_referer" '
-                        '"$http_user_agent" "$http_x_forwarded_for" '
-                        'rt=$request_time uct="$upstream_connect_time" '
-                        'uht="$upstream_header_time" urt="$upstream_response_time"';
-
-        access_log /var/log/nginx/access.log main;
-
-        sendfile on;
-        tcp_nopush on;
-        tcp_nodelay on;
-        keepalive_timeout 65;
-        types_hash_max_size 2048;
-        client_max_body_size 10M;
-
-        gzip on;
-        gzip_vary on;
-        gzip_min_length 1024;
-        gzip_proxied any;
-        gzip_comp_level 6;
-        gzip_types
-            text/plain
-            text/css
-            text/xml
-            text/javascript
-            application/json
-            application/javascript
-            application/xml+rss
-            application/atom+xml
-            image/svg+xml;
-
-        upstream wifi_densepose_backend {
-            least_conn;
-            server wifi-densepose-service:8000 max_fails=3 fail_timeout=30s;
-            keepalive 32;
-        }
-
-        server {
-            listen 80;
-            server_name _;
-            return 301 https://$server_name$request_uri;
-        }
-
-        server {
-            listen 443 ssl http2;
-            server_name wifi-densepose.com;
-
-            ssl_certificate /etc/nginx/ssl/tls.crt;
-            ssl_certificate_key /etc/nginx/ssl/tls.key;
-            ssl_protocols TLSv1.2 TLSv1.3;
-            ssl_ciphers ECDHE-RSA-AES256-GCM-SHA512:DHE-RSA-AES256-GCM-SHA512:ECDHE-RSA-AES256-GCM-SHA384:DHE-RSA-AES256-GCM-SHA384;
-            ssl_prefer_server_ciphers off;
-            ssl_session_cache shared:SSL:10m;
-            ssl_session_timeout 10m;
-
-            location / {
-                proxy_pass http://wifi_densepose_backend;
-                proxy_set_header Host $host;
-                proxy_set_header X-Real-IP $remote_addr;
-                proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
-                proxy_set_header X-Forwarded-Proto $scheme;
-                proxy_connect_timeout 30s;
-                proxy_send_timeout 30s;
-                proxy_read_timeout 30s;
-            }
-
-            location /ws {
-                proxy_pass http://wifi_densepose_backend;
-                proxy_http_version 1.1;
-                proxy_set_header Upgrade $http_upgrade;
-                proxy_set_header Connection "upgrade";
-                proxy_set_header Host $host;
-                proxy_set_header X-Real-IP $remote_addr;
-                proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
-                proxy_set_header X-Forwarded-Proto $scheme;
-                proxy_connect_timeout 7d;
-                proxy_send_timeout 7d;
-                proxy_read_timeout 7d;
-            }
-
-            location /health {
-                access_log off;
-                proxy_pass http://wifi_densepose_backend/health;
-                proxy_set_header Host $host;
-            }
-
-            location /metrics {
-                access_log off;
-                proxy_pass http://wifi_densepose_backend/metrics;
-                proxy_set_header Host $host;
-                allow 10.0.0.0/8;
-                allow 172.16.0.0/12;
-                allow 192.168.0.0/16;
-                deny all;
-            }
-        }
-    }
