+    if (avgCPU > 80) {
+      bottlenecks.push({
+        type: 'CPU',
+        severity: 'HIGH',
+        description: `High CPU usage (${avgCPU.toFixed(1)}%)`
+      });
+    }
+    
+    // Memory bottleneck detection
